function useLocalStorage(key, initial) {
  const [value, setValue] = useState(() => JSON.parse(localStorage.getItem(key) ?? 'null') ?? initial);
  useEffect(() => { localStorage.setItem(key, JSON.stringify(value)); }, [key, value]);
  return [value, setValue];
}

type State = { count: number; step: number };
type Action = { type: "increment" } | { type: "decrement" } | { type: "setStep"; step: number };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "increment":
      return { ...state, count: state.count + state.step };
    case "decrement":
      return { ...state, count: state.count - state.step };
    case "setStep":
      return { ...state, step: action.step };
    default:
      return state;
  }
}

export function Counter() {
  const [state, dispatch] = React.useReducer(reducer, { count: 0, step: 1 });
  return (
    <div>
      <p>Count: {state.count}</p>
      <button onClick={() => dispatch({ type: "increment" })}>+{state.step}</button>
      <button onClick={() => dispatch({ type: "decrement" })}>-{state.step}</button>
    </div>
  );
}

type InputHandle = { focus: () => void; clear: () => void };

const TextField = React.forwardRef<InputHandle, { label: string }>(function TextField({ label }, ref) {
  const inputRef = React.useRef<HTMLInputElement>(null);
  React.useImperativeHandle(ref, () => ({
    focus: () => inputRef.current?.focus(),
    clear: () => { if (inputRef.current) inputRef.current.value = ""; },
  }));
  return (
    <label>
      {label}
      <input ref={inputRef} />
    </label>
  );
});

export function Form() {
  const fieldRef = React.useRef<InputHandle>(null);
  return (
    <>
      <TextField ref={fieldRef} label="Name" />
      <button onClick={() => fieldRef.current?.focus()}>Focus</button>
    </>
  );
}

import { createPortal } from "react-dom";

export function Modal({ open, onClose, children }: {
  open: boolean;
  onClose: () => void;
  children: React.ReactNode;
}) {
  if (!open) return null;
  return createPortal(
    <div className="overlay" onClick={onClose}>
      <div className="dialog" role="dialog" aria-modal="true" onClick={(e) => e.stopPropagation()}>
        {children}
      </div>
    </div>,
    document.body
  );
}

import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Counter } from "./Counter";

test("increments when the button is clicked", async () => {
  const user = userEvent.setup();
  render(<Counter />);

  const button = screen.getByRole("button", { name: /increment/i });
  expect(screen.getByText(/count: 0/i)).toBeInTheDocument();

  await user.click(button);
  expect(screen.getByText(/count: 1/i)).toBeInTheDocument();
});

export function Search({ items }: { items: string[] }) {
  const [query, setQuery] = React.useState("");
  const deferredQuery = React.useDeferredValue(query);
  const [isPending, startTransition] = React.useTransition();

  const results = React.useMemo(
    () => items.filter((i) => i.toLowerCase().includes(deferredQuery.toLowerCase())),
    [items, deferredQuery]
  );

  return (
    <div>
      <input
        value={query}
        onChange={(e) => startTransition(() => setQuery(e.target.value))}
      />
      {isPending && <span>Updating…</span>}
      <ul>{results.map((r) => <li key={r}>{r}</li>)}</ul>
    </div>
  );
}
